insert into alternatives (id, slug, name, brand, basis_text, basis_confidence, basis_sources, affiliate_url, affiliate_type, category, image_url, asin, swap_type) values
  ('15ab1898-bc7a-472d-b2c2-955a2c348d15', 'bobs-red-mill-baking-soda', 'Baking Soda', 'Bob''s Red Mill', 'Founder Bob Moore was a committed Christian; multiple sources document his faith as the explicit motivation for company policy, including giving the company to employees via an ESOP.', 1, ARRAY['https://en.wikipedia.org/wiki/Bob_Moore_(executive)', 'https://www.klove.com/news/faith/founder-of-bob-s-red-mill-committed-christian-generous-boss-9757'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Bob''s%20Red%20Mill%20Baking%20Soda', 'B00VEJOUXE', 'christian'),
  ('83a2ba90-e28f-4bd4-a1ea-bd9bcf7a1471', 'boll-weevil-foaming-hand-wash', 'Foaming Hand Wash', 'Boll Weevil Soap Company', 'Explicitly self-identifies as a Christian-owned family soap business, citing Colossians 3:17 on its own About page. Note: only the Foaming Hand Wash is confirmed available on Amazon — Boll Weevil''s bar soap and body wash are not, and require a direct affiliate relationship instead.', 2, ARRAY['https://bollweevilsoapcompany.com/pages/about-us', 'https://www.amazon.com/Foaming-Boll-Weevil-Soap-Company/dp/B08RF27781'], NULL, 'amazon', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Boll%20Weevil%20Foaming%20Hand%20Wash', 'B08RF27781', 'christian'),
  ('4efcc127-d680-4dea-a399-2ab09893e8b0', 'faithfully-natural-soap-co', 'Soap / Body Wash', 'Faithfully Natural Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://faithfullynaturalsoapco.com/pages/about-us'], 'https://faithfullynaturalsoapco.com', 'direct', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Faithfully%20Natural%20Soap%20Co.', NULL, 'christian'),
  ('a01d81eb-3ade-4fb4-ae07-47e2d47cc693', 'pure-hearts-clean-hands-soap-co', 'Soap / Body Wash', 'Pure Hearts & Clean Hands Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://phchnaturalsoap.net/about-us/'], 'https://phchnaturalsoap.net', 'direct', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Pure%20Hearts%20%26%20Clean%20Hands', NULL, 'christian'),
  ('1385933e-5541-4a77-9d58-8f92605b453d', 'branch-basics-all-purpose-concentrate', 'All-Purpose Cleaner Concentrate', 'Branch Basics', 'Co-founder Allison Evans states in a published interview, "we share a common faith, which we all fall back on," and founders discuss their Christian faith on the Thriving Beyond Belief podcast.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/', 'https://thrivingbeyondbelief.com/046-branch-basics-with-allison-evans-marilee-nelson/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20All-Purpose', 'B0D9WG23V6', 'christian'),
  ('6a292f62-1070-45a3-bfad-1e28adac29d9', 'branch-basics-oxygen-boost', 'Oxygen Boost Stain Remover', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Oxygen%20Boost', 'B0D9WH1HYB', 'christian'),
  ('79b93584-fb27-458f-b169-aaff3a6c2d4c', 'provherbs-herbal-supplements', 'Herbal Supplements / Tinctures', 'Provherbs', 'Company''s own "Our Story" page: "we look first to Christ. He is the center in all that we do."', 1, ARRAY['https://provherbs.com/pages/our-story'], 'https://provherbs.com', 'direct', 'Supplements', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Provherbs%20Supplements', NULL, 'christian'),
  ('f9ad9501-b55e-4d86-a5b9-bac60af8eb43', 'eleven86-artesian-water', 'Real Artesian Water', 'Eleven86', 'Company''s own tagline: "Faith in every drop. Purpose in every bottle."', 1, ARRAY['https://www.eleven86water.com/our-story'], 'https://www.eleven86water.com', 'unconfirmed', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Eleven86%20Water', NULL, 'christian'),
  ('5e45a897-37d5-447f-8160-b0b75c5f7534', 'bold3-coffee', 'Coffee (whole bean & ground)', 'BOLD3 Coffee', '501(c)(3) Christian nonprofit ministry. Own listing states: "BOLD3 Coffee is a Christian Non-profit Ministry on a mission to empower others to be BOLD and spread the Hope of Christ worldwide." Every bag purchased delivers God''s Word into the hands of 3 children.', 1, ARRAY['https://www.amazon.com/BOLD3-coffee-Colombian-Ethiopian-Nicaragua/dp/B07F2J6MHV', 'https://www.bold3.org/'], NULL, 'amazon', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=BOLD3%20Coffee', 'B07F2J6MHV', 'christian'),
  ('c7d4db4d-afc8-440f-be59-c64835a68244', 'palm-beach-herbal-tea', 'Herbal Tea', 'Palm Beach Herbal Tea Company', 'Explicitly self-identifies as a "Christian based, family-owned herbal tea company" on its own site.', 1, ARRAY['https://palmbeachherbalteas.com/pages/our-story'], NULL, 'amazon', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Palm%20Beach%20Herbal%20Tea', 'B07M75ZTDZ', 'christian'),
  ('a67daff3-4102-4984-b878-c2bc60936ceb', 'everylife-diapers-wipes', 'Diapers + Wipes', 'EveryLife', 'Co-founders explicitly state "every child is a miracle from God"; company''s own mission page: "We unapologetically choose to celebrate life. Every child is a gift from above."', 1, ARRAY['https://everylife.com/pages/our-mission', 'https://www.oursundayvisitor.com/meet-the-founders-of-everylife-a-new-pro-life-diaper-company/'], 'https://everylife.com', 'unconfirmed', 'Baby Products', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=EveryLife%20Diapers', NULL, 'christian'),
  ('f493572a-53b8-49c0-82eb-ae8eef8db416', 'earth-eden-diapers', 'Diapers', 'Earth & Eden', 'Not a confirmed Christian-founded brand, but the closest Amazon-available, non-toxic, plant-based diaper option — offered as a secondary pick alongside EveryLife.', 2, ARRAY['https://www.earthandedenbrand.com/', 'https://www.amazon.com/Earth-Eden-Baby-Diapers-Count/dp/B07DYLJHLB'], NULL, 'amazon', 'Baby Products', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Earth%20%26%20Eden%20Diapers', 'B07DYLJHLB', 'christian'),
  ('e33e46bd-1de6-4aae-86c4-f0c7ce45bf93', 'branch-basics-dishwasher-tablets', 'Dishwasher Tablets', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/', 'https://www.amazon.com/Branch-Basics-Dishwasher-Tablets-Fragrance-Free/dp/B0GNT5N4SP'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Dishwasher%20Tablets', 'B0GNT5N4SP', 'christian'),
  ('53012507-054e-4980-aab1-8b81c7363415', 'branch-basics-laundry-detergent-powder', 'Laundry Detergent – 4lbs (120 loads), Powder', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate. Plant & mineral-based powder formula, plastic-free and fragrance-free.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Laundry%20Powder', 'B0GQ665H45', 'christian'),
  ('6d09d758-0845-435d-ab77-f6078f2a9798', 'branch-basics-concentrate-oxygen-boost-bundle', 'Concentrate (33.8 oz) + Oxygen Boost (4 lbs) Bundle', 'Branch Basics', 'Concentrate replaces all-purpose cleaners and can be diluted for surface scrubbing; Oxygen Boost acts as a natural scouring powder and grout cleaner. Sold as a confirmed bundle listing on Amazon. Same founder faith basis as other Branch Basics entries.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Bundle', 'B0D9WH1HYB', 'christian'),
  ('b0bfcc4b-e3c2-48bc-96cd-a12937b0a3d4', 'toups-and-co-organics', 'Makeup & Skincare', 'Toups & Co. Organics', 'Christian family-owned, confirmed on the company''s own About page.', 1, ARRAY['https://toupsandco.com/pages/about-us'], NULL, 'amazon', 'Beauty & Makeup', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Toups%20%26%20Co.%20Organics', 'B0FVLNMF93', 'christian'),
  ('bcae3e42-32c0-4af4-a88e-3d19709a9fe8', 'jes-organics', 'Makeup, Skincare & Supplements', 'JES Organics', 'Own Amazon storefront states "Christian-based company founded in 2006."', 1, ARRAY['https://www.amazon.com/stores/JESOrganics/Homepage/page/34BCD59B-5770-4397-84F6-721513DA72D3'], NULL, 'amazon', 'Beauty & Makeup', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=JES%20Organics', NULL, 'christian'),
  ('9a91b9a1-f116-45dc-bcf9-b6728fbd29a6', 'hosanna-aroma', 'Christian Fragrance', 'Hosanna Aroma', 'Own website states "unapologetically Christian," Scripture-inspired, husband-and-wife team in Colorado, launched April 2024.', 1, ARRAY['https://hosanna-aroma.com/'], 'https://hosanna-aroma.com', 'direct', 'Beauty & Fragrance', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Hosanna%20Aroma', NULL, 'christian'),
  ('b66635e0-1ba3-4ef0-a955-343e12923bdf', 'risen-fragrances', 'Christian Fragrance', 'Risen Fragrances', '"Exists to glorify God"; each scent is paired with Scripture, and $1 per bottle funds Bible distribution.', 1, ARRAY['https://risenfragrances.com/'], 'https://risenfragrances.com', 'direct', 'Beauty & Fragrance', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Risen%20Fragrances', NULL, 'christian'),
  ('895632c2-8c2c-4088-aaa1-6be68431fff7', 'leaf-razor-chrome', 'Leaf Razor (All-Metal Safety Razor, Chrome)', 'Leaf Shave', 'Clean/non-toxic alternative: all-metal, plastic-free razor with a pivoting head and no toxic shaving-strip chemicals. No Christian-founded claim has been found for Leaf Shave — this is offered as a clean swap, not a faith-based one.', 1, ARRAY['https://www.amazon.com/dp/B09QB2Y263', 'https://leafshave.com/'], NULL, 'amazon', 'Beauty & Personal Care', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Leaf%20Razor', 'B09QB2Y263', 'clean'),
  ('a5e45689-36ac-4b46-bf2b-be84cb1b880f', 'divine-shine-lip-gloss', 'Divine Shine Lip Gloss', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/divine-shine-lip-gloss-1?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/Divine_Shine_Lipgloss.png?v=1773108400&width=980', NULL, 'christian'),
