  ('c7a1a4ca-2676-48d5-9a10-ad822960c101', 'faithfully-natural-deodorant-lemon-tea-tree', 'Natural Deodorant (Lemon & Tea Tree)', 'Faithfully Natural Soap Co.', 'Faithfully Natural Soap Co. is an explicitly Christian-owned family business. Their own About page states "we started Faithfully Natural out of a desire to honor God in the way we care for our bodies and steward His creation."', 1, ARRAY['https://faithfullynaturalsoapco.com/pages/about-us'], 'https://faithfullynaturalsoapco.com/products/deodorant?sca_ref=11781009.vhEdmqEWQH570GWc', 'direct', 'Beauty & Personal Care', 'https://faithfullynaturalsoapco.com/cdn/shop/files/03A87A68-5C54-4615-A373-32419E4A93CB.jpg?v=1726070619&width=1346', NULL, 'christian'),
  ('fef1365d-09e4-4db8-b37b-adb5f7dba91e', 'faithfully-natural-deodorant-unscented', 'Unscented Natural Deodorant', 'Faithfully Natural Soap Co.', 'Faithfully Natural Soap Co. is an explicitly Christian-owned family business. Their own About page states "we started Faithfully Natural out of a desire to honor God in the way we care for our bodies and steward His creation."', 1, ARRAY['https://faithfullynaturalsoapco.com/pages/about-us'], 'https://faithfullynaturalsoapco.com/products/unscented?sca_ref=11781009.vhEdmqEWQH570GWc', 'direct', 'Beauty & Personal Care', 'https://faithfullynaturalsoapco.com/cdn/shop/files/72B787D1-75E4-4A24-B5F7-D54DDC86A5B9.jpg?v=1726070543&width=1346', NULL, 'christian'),
