insert into associations (product_id, claim_text, source_urls, confidence_tier, theme_tag, date_checked) values
  ('30c58b0a-b8c8-4eee-b101-f790ad09f43c', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-01'),
  ('ba1b423f-6ef2-4cd7-8acd-707aa002bf5d', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-01'),
  ('684a7c7c-1428-435e-8c7a-89b2a6c63480', 'Entire collection is structured as a tarot-style "deck" of named fortune cards (The Illusionist, The Sovereign, The Sage, and more). Each bottle includes a QR code for a "shower reading" and a daily "manifestation." Method''s own product copy reads: "Are you ready to hear your fortune? Shoot for the stars today with a body wash that offers a glimpse into your future." This is scoped to the limited-edition Shower Readings line only — Method''s everyday cleaners carry no such theme and are not flagged.', ARRAY['https://methodproducts.com/pages/shower-readings', 'https://www.ulta.com/p/limited-edition-shower-readings-body-wash-pimprod2052565'], 1, 'fortune-telling', '2026-07-01'),
  ('cbf6c4e1-719b-4f10-9b43-568186920e49', 'The mascot was deliberately designed as a genie at P&G''s own direction. A 2014 NYT obituary for original illustrator Richard Black quotes P&G''s communications manager: the company wanted "magic from a bottle" represented by a genie, and the artist was directed to draw one. Genies/jinn originate in Arabic and Islamic folklore.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('f7ffbf93-b86a-4fb6-9568-28459c97bc13', 'Named after Ajax (Telamonian Ajax), Greek mythological hero of the Trojan War, second in strength only to Achilles. Current marketing leans into it directly: "Stronger than dirt," with copy describing customers as "everyday heroes."', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-01'),
  ('cb27ae00-9fcf-4171-a2ac-b5363e0d1203', 'Directly named after the Greek/Roman hero Hercules. The company''s own current product pages use the line "Behold the power of Hercules, products built to last and trusted by plumbers."', ARRAY['https://www.oatey.com/products/hercules-glug-kitchen-liquid-drain-opener--782826565'], 1, 'greek-mythology', '2026-07-01'),
  ('a28db44a-94bd-4721-8af8-840d6c1c31c6', 'Entire product line is built around named crystals with stated metaphysical properties (rose quartz for "joy," amethyst for "dream state," peridot for "balance and control your thoughts"). Marketing copy: "Call in your crystal super power. Crystal-infused and plant-powered."', ARRAY['https://www.pacificabeauty.com/collections/aromapower', 'https://www.ulta.com/brand/pacifica?category=fragrance'], 1, 'crystal-metaphysics', '2026-07-01'),
  ('f6ef5be0-bc42-46e2-82f1-61a9ab7db6ac', 'Founded by Yogi Bhajan, who introduced Kundalini Yoga to the US; the tea recipe and brand are explicitly built on Ayurvedic philosophy. The company''s own "our story" copy still cites Ayurveda as the foundation.', ARRAY['https://en.wikipedia.org/wiki/Yogi_Tea'], 1, 'ayurvedic', '2026-07-01'),
  ('70db2a3b-2749-4eed-8bb1-a0dec8544842', 'Documented marketing campaigns built on witchcraft/occult themes: the company hired a self-described witch doctor in 2019 to publicly "hex" inventory as a Halloween stunt, and sold "sell your soul" branded merchandise with a mock contract for the buyer''s "Eternal Soul." These campaigns themselves are documented fact; describing the brand as "satanic" is contested commentary, not a company statement.', ARRAY['https://www.adweek.com/creativity/drink-at-your-own-risk-liquid-death-hires-witch-doctor-to-hex-its-water/', 'https://www.westernjournal.com/liquid-death-water-brand-offered-buy-customers-souls-even-offers-contract-put-satanic-deal-writing/'], 2, 'occult-marketing', '2026-07-01'),
  ('2dac29e1-7f97-4653-966f-cef7c7604fd2', 'Named directly after Gaia, the Greek primordial Earth goddess and mother of all life in Greek mythology. Confirmed by the founder''s own company history (founded 1986/1987 by herbalist Ric Scalzo).', ARRAY['https://www.peoplespharmacy.com/articles/introducing-gaia-herbs'], 1, 'greek-mythology', '2026-07-01'),
  ('27d66ce2-d337-48f3-92ea-d1815eb984c3', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner — P&G''s own communications manager confirmed to the NYT that the mascot was deliberately designed as a genie.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('64d44505-7a42-4e95-ab2a-28224a90b97c', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('0365a4e5-28f6-44bf-b9ae-7e020e588bd7', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. The company''s own website states: "Our name is inspired by an ancient Iroquois philosophy which instructs that in our every deliberation, we must consider the impact of our decisions on the next seven generations."', ARRAY['https://www.seventhgeneration.com/blog/origin-our-name-seventh-generation', 'https://www.fastcompany.com/665006/great-law-iroquois-confederacy'], 1, 'indigenous-philosophy', '2026-07-01'),
  ('afdf2305-c75e-4570-91df-3128c6b63475', 'Logo is a twin-tailed siren from Greek mythology, confirmed on the company''s own "Story of the Siren" page: "it depicted a siren, a seductive twin-tailed mermaid from Greek mythology who enticed passing sailors to their doom with her enchanting song."', ARRAY['https://about.starbucks.com/history/the-story-of-the-siren/'], 1, 'greek-mythology', '2026-07-01'),
  ('a4303ed3-f7ca-4d70-ac2b-1d65bda0569f', 'Name and branding deliberately center on death-themed imagery. The company''s own website states: "To some, a death wish may sound irresponsible, morbid, a step too far — but we believe it is the boldest sign of living life to the fullest." This is secular dark/death-themed branding, not tied to a specific mythology or occult practice.', ARRAY['https://www.forbes.com/sites/forbestreptalks/2016/02/09/meet-the-entrepreneur-behind-the-super-bowl-coffee-ad/', 'https://en.wikipedia.org/wiki/Death_Wish_Coffee'], 1, 'secular-death-themed', '2026-07-01'),
  ('7367cc4f-ecfc-455c-81dc-ea0d3fe642cb', 'Founder Jessica Alba publicly shared Instagram content in August 2024 involving occult/spiritual practices (numerology, astrology, crystals, and sage burning). Alba had stepped down as Chief Creative Officer in April 2024, before the posts, so she was no longer a company officer at the time, and the brand''s own products carry no occult imagery or branding. This is the founder''s personal social media activity, not a company branding decision.', ARRAY['https://www.instagram.com/p/C_bp7Qpu-hr/'], 2, 'founder-personal-conduct', '2026-07-01'),
  ('25e3002f-7977-441b-8006-2ac08bf833e6', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history. Same brand-wide association as the Arm & Hammer baking soda entry.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-03'),
  ('3431d569-33fd-4c8f-abd9-aa7cc3a1dc5f', 'Named after Ajax (Telamonian Ajax), the Greek mythological hero of the Trojan War. Same brand-wide association as the Ajax Powder Cleanser entry.', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-03'),
  ('9fc05cca-3ccf-44b0-aa36-1bed7feda2a2', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. Same brand-wide association as the Seventh Generation Laundry Detergent entry.', ARRAY['https://www.seventhgeneration.com/blog/more-than-a-name', 'https://en.wikipedia.org/wiki/Seventh_Generation_Inc.'], 1, 'indigenous-philosophy', '2026-07-03'),
  ('5e0e3b2b-2514-4e80-828d-ca19c35887e1', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('0c58645f-a68b-4a1a-9632-a5a4dd44e6a4', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('4774db0e-66f6-431f-a94c-0f52f5f22a66', 'Founder Amanda Chantal Bacon describes the company as "a cosmic beacon" in her own interviews, references astrology and crystal energy throughout the brand''s marketing, and publicly stated of a stolen store crystal, "You do not want the energy of a stolen crystal." Company''s own marketing describes Moon Juice as "a healing force, an etheric potion, a cosmic beacon."', ARRAY['https://www.theguardian.com/lifeandstyle/2015/jan/16/moon-juice-food-for-beautiful-people', 'https://moonjuice.com/pages/about'], 1, 'astrology-crystal-energy', '2026-07-03'),
  ('84aa485a-63a4-42d9-b3bc-5c80eaeeef91', 'Bottle is a five-pointed star, described in the company''s own marketing as "a celestial bottle: a five-pointed star evoking womanhood, protection and destiny." Company''s own copy calls it "a cosmic object that appears supernaturally out of space" and "the embodiment of dreams."', ARRAY['https://www.mugler.com/en-us/angel', 'https://en.wikipedia.org/wiki/Angel_(fragrance)'], 1, 'celestial-supernatural', '2026-07-03'),
  ('a41aec5e-9a11-4dd2-9cdd-3bbf4f67637f', 'Named after Venus, the Roman goddess of love and beauty. Company''s own brand platform and tagline: "Reveal the goddess in you." The company''s own brand team confirmed the internal creative platform as "every woman can feel like a goddess."', ARRAY['https://gillette.com/en-us/venus', 'https://en.wikipedia.org/wiki/Gillette_Venus'], 1, 'roman-mythology', '2026-07-03'),
  ('eb2c7617-3b2c-4601-ae41-70f8dded6235', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('a397b8d9-14b5-4245-9f7f-04b8d3d71189', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('0f8170ed-9f48-4f39-906f-8674d174c218', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('c3d5de2f-bc96-49bb-aee7-d1bdc7d31086', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('db72a5e0-9963-4864-b33d-601864594d7b', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('37a63cc8-43f8-4697-be6d-438d8f52c22e', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('fbe8498e-33bf-4d1d-af01-01165781d879', 'Entire product line is built around named crystals with stated metaphysical properties (rose quartz for "joy," amethyst for "dream state," peridot for "balance and control your thoughts"). Marketing copy: "Call in your crystal super power. Crystal-infused and plant-powered."', ARRAY['https://www.pacificabeauty.com/collections/aromapower', 'https://www.ulta.com/brand/pacifica?category=fragrance'], 1, 'crystal-metaphysics', '2026-07-01'),
  ('ce188af2-3abe-4940-96aa-c58c006528ee', 'Founder Amanda Chantal Bacon describes the company as "a cosmic beacon" in her own interviews, references astrology and crystal energy throughout the brand''s marketing, and publicly stated of a stolen store crystal, "You do not want the energy of a stolen crystal." Company''s own marketing describes Moon Juice as "a healing force, an etheric potion, a cosmic beacon."', ARRAY['https://www.theguardian.com/lifeandstyle/2015/jan/16/moon-juice-food-for-beautiful-people', 'https://moonjuice.com/pages/about'], 1, 'astrology-crystal-energy', '2026-07-03'),
  ('c0f9b31e-7f23-48da-be87-c2c2adefd1b3', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-03'),
  ('e75731bd-5f83-42e2-bab8-1c8fb860b618', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-03'),
  ('6a712dbf-7207-4400-afe8-da1b8ee0de64', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-03'),
  ('ab6deb97-7bd6-4d47-93a2-51f378b1bee2', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-03'),
  ('b1cdab6e-e3c2-4f3d-afef-19dbd174fa31', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-03'),
  ('881d3837-1be6-4234-a7a2-8590881a02b8', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically. Dr. Bronner''s Castile Shampoo is made under the same brand and founder philosophy as the bar and liquid castile soaps.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-03'),
  ('69695747-82c1-4c8c-acb1-06ddc190bfbd', 'Old Spice''s Wild Collection product line is specifically named after mythological and fantasy creatures. The Krakengard product is named after the Kraken from Norse mythology. Old Spice''s own product page states "The first rule of the kraken is, Shhh, don''t tell anyone how good I smell." Other products in the same line include Wolfthorn, Raptorstrike, and Dragonblast. This entry is scoped to the Wild Collection specifically, not all Old Spice products.', ARRAY['https://oldspice.com/shop-at-retailers/old-spice-antiperspirant-and-deodorant-for-men-krakengard-2-6-oz/', 'https://www.amazon.com/dp/B06X1BV9CL'], 1, 'mythological-creatures', '2026-07-03');
